import React, { useState, useEffect } from "react";
import api from "../api";
import toast from "react-hot-toast";

export default function StudentList() {
  const [students, setStudents] = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [search,   setSearch]   = useState("");

  const load = async () => {
    setLoading(true);
    try { const r = await api.get("/api/students"); setStudents(r.data); }
    catch { toast.error("Failed to load students"); }
    finally { setLoading(false); }
  };
  useEffect(() => { load(); }, []);

  const remove = async (uid, name) => {
    if (!window.confirm(`Remove ${name}?`)) return;
    await api.delete(`/api/students/${uid}`);
    toast.success(`${name} removed`);
    load();
  };

  const filtered = students.filter(s =>
    s.name.toLowerCase().includes(search.toLowerCase()) ||
    s.studentId.toLowerCase().includes(search.toLowerCase()) ||
    s.course.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div>
      <div className="stats-row">
        <div className="stat-card"><div className="stat-value">{students.length}</div><div className="stat-label">Total Students</div></div>
        <div className="stat-card"><div className="stat-value">{[...new Set(students.map(s=>s.course))].length}</div><div className="stat-label">Courses</div></div>
        <div className="stat-card"><div className="stat-value">{filtered.length}</div><div className="stat-label">Showing</div></div>
      </div>

      <div className="card">
        <div style={{ display:"flex", justifyContent:"space-between", alignItems:"center", marginBottom:"20px" }}>
          <div className="card-title" style={{ marginBottom:0 }}>🎓 Registered Students</div>
          <input value={search} onChange={e=>setSearch(e.target.value)}
            placeholder="🔍 Search name, ID, course…"
            style={{ width:260, fontSize:13 }} />
        </div>

        {loading ? <div className="loading"><span className="spinner"/>Loading…</div>
        : filtered.length === 0 ? (
          <div className="empty-state"><div className="icon">🎓</div><p>{search?"No matches":"No students registered yet"}</p></div>
        ) : (
          <table className="data-table">
            <thead><tr><th>#</th><th>Student ID</th><th>Name</th><th>Course</th><th>Registered</th><th>Status</th><th></th></tr></thead>
            <tbody>
              {filtered.map((s,i) => (
                <tr key={s.id}>
                  <td style={{ color:"var(--text3)", fontFamily:"monospace", fontSize:12 }}>{String(i+1).padStart(2,"0")}</td>
                  <td style={{ fontFamily:"monospace", fontSize:13, color:"var(--accent)" }}>{s.studentId}</td>
                  <td style={{ fontWeight:600, color:"var(--text)" }}>{s.name}</td>
                  <td>{s.course}</td>
                  <td style={{ fontSize:12 }}>{new Date(s.registeredAt).toLocaleDateString("en-GB",{day:"numeric",month:"short",year:"numeric"})}</td>
                  <td><span className="badge badge-success">✓ Active</span></td>
                  <td><button className="btn btn-danger" style={{ padding:"6px 12px", fontSize:12 }} onClick={()=>remove(s.id,s.name)}>Remove</button></td>
                </tr>
              ))}
            </tbody>
          </table>
        )}
      </div>
    </div>
  );
}
